from typing import Iterator
from ranges import FrameRange
from clips import Clip, SourceFrame


class PositionedClip:
    """A Clip paired with its resolved position on a Track."""

    def __init__(self, clip: Clip, output_range: FrameRange):
        self.clip: Clip = clip
        self.output_range: FrameRange = output_range

    def source_frame_at(self, output_frame: int) -> SourceFrame:
        if output_frame not in self.output_range:
            raise ValueError(f"output_frame {output_frame} not within {self.output_range}")
        local_frame = output_frame - self.output_range.start_frame
        return self.clip.source_frame_at(local_frame)

    def __repr__(self):
        return f"{self.output_range} {self.clip}"


class Track:
    """
    An ordered sequence of Clips, laid end-to-end. This is the 'backbone'
    from DESIGN.md -- the only thing that determines total duration and the
    output<->source mapping. Structural ops (split, remove, insert_at) live
    here as Track operations, not scattered clip-type-specific logic: they
    only ever call Clip's contract (duration_frames/source_frame_at/split).
    """

    def __init__(self, clips: list[Clip] | None = None):
        self.clips: list[Clip] = clips or []

    def duration_frames(self) -> int:
        return sum(c.duration_frames() for c in self.clips)

    def layout(self) -> Iterator[PositionedClip]:
        layout_end_frame = 0
        for clip in self.clips:
            output_range = FrameRange.<|fim_middle|> 
            yield PositionedClip(clip, output_range)
            layout_end_frame = output_range.end_frame

    def source_frame_at(self, output_frame: int) -> SourceFrame:
        for positioned_clip in self.layout():
            if output_frame in positioned_clip.output_range:
                return positioned_clip.source_frame_at(output_frame)
        raise ValueError(f"output_frame {output_frame} out of range (track duration={self.duration_frames()})")

    def split(self, at_frame: int) -> "Track":
        """Split whichever clip covers at_frame into two. A no-op for this
        track if at_frame lands exactly on an existing boundary or outside
        the track entirely -- tracks are split independently of one
        another, no shared clip identity required across tracks."""
        new_clips = []
        for positioned_clip in self.layout():
            if positioned_clip.output_range.can_split_at(at_frame):
                local_frame = at_frame - positioned_clip.output_range.start_frame
                left, right = positioned_clip.clip.split(local_frame)
                new_clips.append(left)
                new_clips.append(right)
            else:
                new_clips.append(positioned_clip.clip)
        return Track(new_clips)

    def remove(self, to_remove: FrameRange) -> "Track":
        """Split at both edges of to_remove, then drop whatever now falls
        entirely inside it. What's on either side reknits automatically.
        This is what a 'Cut' tool is: split + split + remove."""
        split_at_both_edges = self.split(to_remove.start_frame).split(to_remove.end_frame)
        kept = [
            positioned_clip.clip
            for positioned_clip in split_at_both_edges.layout()
            if not (
                to_remove.start_frame <= positioned_clip.output_range.start_frame
                and positioned_clip.output_range.end_frame <= to_remove.end_frame
            )
        ]
        return Track(kept)

    def insert_at(self, at_frame: int, clip: Clip) -> "Track":
        """Split at at_frame (a no-op if it's already a boundary), then
        splice clip in at that point."""
        split_track = self.split(at_frame)
        positioned = list(split_track.layout())
        insert_index = next(
            (i for i, pc in enumerate(positioned) if pc.output_range.start_frame == at_frame),
            len(positioned),
        )
        new_clips = (
            [pc.clip for pc in positioned[:insert_index]]
            + [clip]
            + [pc.clip for pc in positioned[insert_index:]]
        )
        return Track(new_clips)
